INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A1', 'listening', 'Hello & Goodbye', 'Learn basic greetings by listening',
'{"type":"listen_and_choose","instructions":"Listen to the audio and choose the correct picture.","exercises":[{"prompt":"Hello! How are you?","options":["A person waving","A person sleeping","A person eating","A person running"],"correct":0,"hint":"This is a friendly greeting"},{"prompt":"Goodbye! See you later!","options":["A person arriving","A person waving goodbye","A person sitting","A person cooking"],"correct":1,"hint":"Someone is leaving"},{"prompt":"Good morning!","options":["A night sky","A sunrise","A rainy day","A sunset"],"correct":1,"hint":"Think about when you wake up"},{"prompt":"Good night! Sweet dreams!","options":["A sunny day","A person at work","A moon and stars","A playground"],"correct":2,"hint":"Time to sleep"},{"prompt":"Nice to meet you!","options":["Two people shaking hands","A person alone","A person angry","A person running"],"correct":0,"hint":"Meeting someone new"},{"prompt":"What time is it?","options":["A clock showing 3 o''clock","A clock showing 12 o''clock","A clock showing 6 o''clock","A clock showing 9 o''clock"],"correct":0,"hint":"You''re asking for the hour"},{"prompt":"I love to read books.","options":["A person reading a book","A person watching TV","A person playing a game","A person riding a bike"],"correct":0,"hint":"This is a quiet activity"},{"prompt":"Let''s go for a walk!","options":["A person walking in a park","A person running a race","A person sitting on a bench","A person jumping"],"correct":0,"hint":"This is an outdoor activity"},{"prompt":"It''s raining today.","options":["An umbrella","A sunny day","A snowman","A rainbow"],"correct":0,"hint":"You need this when it rains"},{"prompt":"Do you want some ice cream?","options":["A bowl of ice cream","A plate of vegetables","A glass of water","A slice of pizza"],"correct":0,"hint":"This is a sweet treat"},{"prompt":"Time for bed!","options":["A bed with pillows","A sofa","A chair","A table"],"correct":0,"hint":"This is where you sleep"},{"prompt":"I enjoy cooking.","options":["A person cooking in a kitchen","A person eating at a restaurant","A person washing dishes","A person shopping for groceries"],"correct":0,"hint":"This is preparing food"},{"prompt":"It''s a beautiful day!","options":["A sunny beach","A cloudy sky","A snowy mountain","A stormy night"],"correct":0,"hint":"Think of clear skies"},{"prompt":"I''m feeling tired.","options":["A person sleeping","A person dancing","A person exercising","A person laughing"],"correct":0,"hint":"This is when you need rest"},{"prompt":"What a lovely flower!","options":["A colorful flower","A tree","A rock","A piece of fruit"],"correct":0,"hint":"This grows in gardens"},{"prompt":"Can you help me?","options":["A person helping another person","A person ignoring someone","A person walking away","A person playing alone"],"correct":0,"hint":"This is asking for assistance"},{"prompt":"It''s snack time!","options":["A bowl of chips","A full meal","A glass of juice","A dessert plate"],"correct":0,"hint":"This is a small meal"},{"prompt":"I love to travel.","options":["A person at an airport","A person at home","A person in a garden","A person in a gym"],"correct":0,"hint":"This involves going to new places"},{"prompt":"Let''s play a game!","options":["A group of friends playing a board game","A person studying","A person working","A person sleeping"],"correct":0,"hint":"This is for fun and entertainment"},{"prompt":"How was your day?","options":["A person smiling","A person frowning","A person sleeping","A person working"],"correct":0,"hint":"This expression shows happiness about the day"}]}', 1),

('en', 'A1', 'listening', 'Numbers 1 to 10', 'Listen and learn numbers one through ten',
'{"type":"listen_and_choose","instructions":"Listen to the number and choose the correct one.","exercises":[{"prompt":"Three","options":["1","3","5","7"],"correct":1,"hint":"It comes after two"},{"prompt":"Seven","options":["4","6","7","9"],"correct":2,"hint":"It comes after six"},{"prompt":"One","options":["1","2","10","8"],"correct":0,"hint":"The very first number"},{"prompt":"Ten","options":["2","5","8","10"],"correct":3,"hint":"The biggest single-digit group"},{"prompt":"Five","options":["3","5","4","6"],"correct":1,"hint":"Right in the middle"},{"prompt":"Five","options":["3","5","8","10"],"correct":1,"hint":"It comes after four"},{"prompt":"Two","options":["1","2","3","4"],"correct":1,"hint":"It comes after one"},{"prompt":"Ten","options":["9","10","11","12"],"correct":1,"hint":"It comes after nine"},{"prompt":"Four","options":["2","4","6","8"],"correct":1,"hint":"It comes after three"},{"prompt":"Eight","options":["7","8","9","10"],"correct":1,"hint":"It comes after seven"},{"prompt":"Nine","options":["8","9","10","11"],"correct":1,"hint":"It comes after eight"},{"prompt":"Zero","options":["0","1","2","3"],"correct":0,"hint":"The first number in counting"},{"prompt":"Three","options":["2","3","4","5"],"correct":1,"hint":"It comes after two"},{"prompt":"Six","options":["5","6","7","8"],"correct":1,"hint":"It comes after five"},{"prompt":"Eleven","options":["10","11","12","13"],"correct":1,"hint":"It comes after ten"},{"prompt":"Twelve","options":["11","12","13","14"],"correct":1,"hint":"It comes after eleven"},{"prompt":"Thirteen","options":["12","13","14","15"],"correct":1,"hint":"It comes after twelve"},{"prompt":"Fifteen","options":["14","15","16","17"],"correct":1,"hint":"It comes after fourteen"},{"prompt":"Sixteen","options":["15","16","17","18"],"correct":1,"hint":"It comes after fifteen"},{"prompt":"Seventeen","options":["16","17","18","19"],"correct":1,"hint":"It comes after sixteen"}]}', 2),

('en', 'A1', 'listening', 'Colors Around Us', 'Listen and identify colors',
'{"type":"listen_and_choose","instructions":"Listen to the color name and pick the right one.","exercises":[{"prompt":"Red","options":["🔴","🔵","🟢","🟡"],"correct":0,"hint":"The color of a fire truck"},{"prompt":"Blue","options":["🟠","🔵","🟣","🔴"],"correct":1,"hint":"The color of the sky"},{"prompt":"Green","options":["🟡","🔴","🟢","🔵"],"correct":2,"hint":"The color of grass"},{"prompt":"Yellow","options":["🟢","🟣","🔴","🟡"],"correct":3,"hint":"The color of the sun"},{"prompt":"Orange","options":["🟠","🔵","🟢","🟡"],"correct":0,"hint":"A fruit has this name too"},{"prompt":"Yellow","options":["🟡","🔵","🟢","🔴"],"correct":0,"hint":"The color of a banana"},{"prompt":"Purple","options":["🟣","🟡","🔴","🔵"],"correct":0,"hint":"The color of eggplant"},{"prompt":"Orange","options":["🟠","🟡","🔵","🔴"],"correct":0,"hint":"The color of an orange fruit"},{"prompt":"Pink","options":["🟣","🟡","🔴","🟠"],"correct":2,"hint":"The color of cotton candy"},{"prompt":"Brown","options":["🟤","🟢","🔵","🟡"],"correct":0,"hint":"The color of chocolate"},{"prompt":"Black","options":["⚫","⚪","🟤","🔵"],"correct":0,"hint":"The color of a coal"},{"prompt":"White","options":["⚪","🟤","🔵","🔴"],"correct":0,"hint":"The color of snow"},{"prompt":"Gray","options":["⚫","⚪","🟤","🟢"],"correct":2,"hint":"The color of a rainy day"},{"prompt":"Turquoise","options":["🟢","🔵","🟣","🟠"],"correct":1,"hint":"The color of the ocean"},{"prompt":"Magenta","options":["🟣","🟡","🔴","🔵"],"correct":0,"hint":"A vibrant shade of pink"},{"prompt":"Teal","options":["🟢","🔵","🟡","🟣"],"correct":1,"hint":"A bluish-green color"},{"prompt":"Lavender","options":["🟣","🔵","⚪","🟡"],"correct":0,"hint":"A light shade of purple"},{"prompt":"Coral","options":["🟠","🟣","🔴","⚪"],"correct":0,"hint":"A pinkish-orange color"},{"prompt":"Ivory","options":["⚪","🟡","🟤","🔵"],"correct":0,"hint":"A shade similar to white, but warmer"},{"prompt":"Peach","options":["🟠","🟡","🔴","🟣"],"correct":0,"hint":"A soft orange color"}]}', 3),

('en', 'A1', 'listening', 'My Family', 'Listen and learn family member names',
'{"type":"listen_and_choose","instructions":"Listen and choose who is being described.","exercises":[{"prompt":"This is my mother. She is very kind.","options":["👩 Mother","👨 Father","👦 Brother","👧 Sister"],"correct":0,"hint":"A female parent"},{"prompt":"My father likes to cook.","options":["👧 Sister","👦 Brother","👨 Father","👩 Mother"],"correct":2,"hint":"A male parent"},{"prompt":"I have a baby sister.","options":["👦 Brother","👨 Father","👩 Mother","👧 Sister"],"correct":3,"hint":"A young female sibling"},{"prompt":"My brother plays football.","options":["👦 Brother","👧 Sister","👩 Mother","👨 Father"],"correct":0,"hint":"A male sibling"},{"prompt":"Grandmother tells us stories.","options":["👨 Father","👩 Mother","👵 Grandmother","👦 Brother"],"correct":2,"hint":"Your parent''s mother"},{"prompt":"This is my older brother. He plays soccer.","options":["👦 Brother","👩 Mother","👨 Father","👧 Sister"],"correct":0,"hint":"A male sibling"},{"prompt":"My sister is very artistic.","options":["👧 Sister","👦 Brother","👨 Father","👩 Mother"],"correct":0,"hint":"A female sibling"},{"prompt":"This is my uncle. He tells funny jokes.","options":["👨 Father","👩 Mother","👦 Brother","👴 Uncle"],"correct":3,"hint":"A male relative, brother of a parent"},{"prompt":"My aunt loves to travel.","options":["👩 Mother","👧 Sister","👵 Aunt","👨 Father"],"correct":2,"hint":"A female relative, sister of a parent"},{"prompt":"I have a little brother who is always happy.","options":["👦 Brother","👧 Sister","👨 Father","👩 Mother"],"correct":0,"hint":"A young male sibling"},{"prompt":"This is my grandmother. She bakes cookies.","options":["👵 Grandmother","👩 Mother","👨 Father","👴 Grandfather"],"correct":0,"hint":"A female grandparent"},{"prompt":"My grandfather tells great stories.","options":["👨 Father","👵 Aunt","👴 Grandfather","👩 Mother"],"correct":2,"hint":"A male grandparent"},{"prompt":"This is my cousin. She loves animals.","options":["👦 Brother","👧 Cousin","👩 Mother","👨 Father"],"correct":1,"hint":"A child of an aunt or uncle"},{"prompt":"My dad enjoys fishing.","options":["👦 Brother","👨 Father","👩 Mother","👧 Sister"],"correct":1,"hint":"A male parent"},{"prompt":"This is my best friend. He is very funny.","options":["👦 Brother","👧 Sister","👨 Friend","👩 Mother"],"correct":2,"hint":"A male companion"},{"prompt":"My mom loves gardening.","options":["👩 Mother","👧 Sister","👦 Brother","👨 Father"],"correct":0,"hint":"A female parent"},{"prompt":"This is my daughter. She is learning to read.","options":["👩 Mother","👧 Daughter","👦 Son","👨 Father"],"correct":1,"hint":"A female child"},{"prompt":"My son likes to play video games.","options":["👦 Son","👩 Mother","👧 Daughter","👨 Father"],"correct":0,"hint":"A male child"},{"prompt":"This is my niece. She loves to dance.","options":["👩 Mother","👧 Niece","👦 Nephew","👨 Father"],"correct":1,"hint":"The daughter of my sibling"},{"prompt":"My husband enjoys reading.","options":["👩 Mother","👨 Husband","👧 Daughter","👦 Son"],"correct":1,"hint":"A male spouse"}]}', 4),

('en', 'A1', 'listening', 'Animals I Know', 'Listen to animal names and sounds',
'{"type":"listen_and_choose","instructions":"Listen and choose the correct animal.","exercises":[{"prompt":"The cat says meow.","options":["🐱","🐶","🐦","🐸"],"correct":0,"hint":"A small furry pet"},{"prompt":"The dog is barking.","options":["🐱","🐶","🐟","🐘"],"correct":1,"hint":"A loyal pet that fetches"},{"prompt":"Look at the big elephant!","options":["🐁","🐦","🐘","🐟"],"correct":2,"hint":"The largest land animal"},{"prompt":"The bird is singing.","options":["🐸","🐦","🐱","🐶"],"correct":1,"hint":"It has wings and feathers"},{"prompt":"The fish swims in the water.","options":["🐦","🐱","🐶","🐟"],"correct":3,"hint":"It lives underwater"},{"prompt":"The cow goes moo.","options":["🐄","🐖","🐴","🐑"],"correct":0,"hint":"A farm animal that gives milk"},{"prompt":"The frog jumps and says ribbit.","options":["🐸","🐦","🐍","🐢"],"correct":0,"hint":"A green amphibian"},{"prompt":"The horse gallops quickly.","options":["🐴","🐮","🐓","🐕"],"correct":0,"hint":"A strong animal used for riding"},{"prompt":"The duck quacks.","options":["🐦","🐤","🦆","🐢"],"correct":2,"hint":"A bird often found in water"},{"prompt":"The pig oinks.","options":["🐖","🐄","🐕","🐑"],"correct":0,"hint":"A pink animal that loves mud"},{"prompt":"The owl hoots at night.","options":["🦉","🐦","🐦","🐸"],"correct":0,"hint":"A wise bird known for its large eyes"},{"prompt":"The lion roars loudly.","options":["🐅","🐘","🦁","🐻"],"correct":2,"hint":"The king of the jungle"},{"prompt":"The sheep says baa.","options":["🐑","🐄","🐐","🐖"],"correct":0,"hint":"A fluffy animal often seen in flocks"},{"prompt":"The snake slithers silently.","options":["🐍","🐸","🐦","🐕"],"correct":0,"hint":"A legless reptile"},{"prompt":"The parrot talks and mimics sounds.","options":["🐦","🦜","🐤","🦉"],"correct":1,"hint":"A colorful bird that can speak"},{"prompt":"The bear growls in the forest.","options":["🐻","🦁","🐅","🐺"],"correct":0,"hint":"A large, furry animal that hibernates"},{"prompt":"The rabbit hops around.","options":["🐇","🐁","🐇","🐻"],"correct":0,"hint":"A small animal with long ears"},{"prompt":"The fish swims in the water.","options":["🐡","🐠","🐟","🐬"],"correct":2,"hint":"An animal found in oceans and rivers"},{"prompt":"The turtle moves slowly.","options":["🐢","🐍","🐊","🐸"],"correct":0,"hint":"A reptile with a hard shell"},{"prompt":"The whale sings in the ocean.","options":["🐳","🐬","🐟","🦈"],"correct":0,"hint":"The largest mammal in the sea"}]}', 5);

