INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A1', 'speaking', 'Say Hello', 'Practice greeting people',
'{"type":"speak_and_compare","instructions":"Listen to the phrase, then say it aloud. We will check your pronunciation!","exercises":[{"prompt":"Hello!","expected":"hello","hint":"A simple greeting"},{"prompt":"Good morning!","expected":"good morning","hint":"What you say in the morning"},{"prompt":"How are you?","expected":"how are you","hint":"Asking about someone''s feelings"},{"prompt":"Nice to meet you!","expected":"nice to meet you","hint":"When you meet someone new"},{"prompt":"Goodbye!","expected":"goodbye","hint":"When you are leaving"},{"prompt":"What is your name?","expected":"what is your name","hint":"Asking for someone''s name"},{"prompt":"Thank you!","expected":"thank you","hint":"Expressing gratitude"},{"prompt":"See you later!","expected":"see you later","hint":"A way to say goodbye"},{"prompt":"I''m sorry.","expected":"i''m sorry","hint":"Apologizing for something"},{"prompt":"Can you help me?","expected":"can you help me","hint":"Requesting assistance"},{"prompt":"What time is it?","expected":"what time is it","hint":"Asking for the current time"},{"prompt":"Where are you from?","expected":"where are you from","hint":"Inquiring about someone''s origin"},{"prompt":"I love you.","expected":"i love you","hint":"Expressing affection"},{"prompt":"It''s nice to meet you!","expected":"it''s nice to meet you","hint":"A polite greeting when meeting someone"},{"prompt":"What do you do?","expected":"what do you do","hint":"Asking about someone''s occupation"},{"prompt":"Do you speak English?","expected":"do you speak english","hint":"Inquiring about language skills"},{"prompt":"Have a great day!","expected":"have a great day","hint":"Wishing someone well"},{"prompt":"Where is the bathroom?","expected":"where is the bathroom","hint":"Asking for directions"},{"prompt":"I don''t understand.","expected":"i don''t understand","hint":"Indicating confusion"},{"prompt":"Could you repeat that?","expected":"could you repeat that","hint":"Requesting someone to say something again"}]}', 1),

('en', 'A1', 'speaking', 'Tell Me About You', 'Practice introducing yourself',
'{"type":"speak_and_compare","instructions":"Say each sentence out loud. Try to match the words exactly!","exercises":[{"prompt":"My name is...","expected":"my name is","hint":"Tell your name"},{"prompt":"I am six years old.","expected":"i am six years old","hint":"Tell your age"},{"prompt":"I like to play.","expected":"i like to play","hint":"Something you enjoy"},{"prompt":"I am happy!","expected":"i am happy","hint":"How you feel"},{"prompt":"Thank you!","expected":"thank you","hint":"Being polite"},{"prompt":"I have a pet cat.","expected":"i have a pet cat","hint":"Talk about your pet"},{"prompt":"My favorite color is blue.","expected":"my favorite color is blue","hint":"Share your favorite color"},{"prompt":"I enjoy reading books.","expected":"i enjoy reading books","hint":"Mention a hobby"},{"prompt":"I live in a big city.","expected":"i live in a big city","hint":"Talk about where you live"},{"prompt":"I love to ride my bike.","expected":"i love to ride my bike","hint":"Describe an activity you like"},{"prompt":"I want to be a doctor.","expected":"i want to be a doctor","hint":"Share your dream job"},{"prompt":"I play soccer on weekends.","expected":"i play soccer on weekends","hint":"Talk about your favorite sport"},{"prompt":"My birthday is in July.","expected":"my birthday is in july","hint":"Tell about your birthday month"},{"prompt":"I can speak two languages.","expected":"i can speak two languages","hint":"Mention your language skills"},{"prompt":"I go to school every day.","expected":"i go to school every day","hint":"Talk about your routine"},{"prompt":"I like to watch movies.","expected":"i like to watch movies","hint":"Share an activity you enjoy"},{"prompt":"I have many friends at school.","expected":"i have many friends at school","hint":"Talk about your friends"},{"prompt":"I enjoy listening to music.","expected":"i enjoy listening to music","hint":"Mention a favorite pastime"},{"prompt":"I love eating ice cream.","expected":"i love eating ice cream","hint":"Share a favorite treat"},{"prompt":"I watch cartoons every Saturday.","expected":"i watch cartoons every saturday","hint":"Talk about what you do on weekends"}]}', 2),

('en', 'A1', 'speaking', 'Count With Me', 'Practice saying numbers aloud',
'{"type":"speak_and_compare","instructions":"Say each number clearly.","exercises":[{"prompt":"One","expected":"one","hint":"The first number"},{"prompt":"Two","expected":"two","hint":"After one"},{"prompt":"Five","expected":"five","hint":"Half of ten"},{"prompt":"Eight","expected":"eight","hint":"After seven"},{"prompt":"Ten","expected":"ten","hint":"Two hands of fingers"},{"prompt":"Three","expected":"three","hint":"After two"},{"prompt":"Four","expected":"four","hint":"The number of sides on a square"},{"prompt":"Six","expected":"six","hint":"One more than five"},{"prompt":"Seven","expected":"seven","hint":"The number of days in a week"},{"prompt":"Eight","expected":"eight","hint":"Two times four"},{"prompt":"Nine","expected":"nine","hint":"One less than ten"},{"prompt":"Ten","expected":"ten","hint":"The base of our number system"},{"prompt":"Eleven","expected":"eleven","hint":"One more than ten"},{"prompt":"Twelve","expected":"twelve","hint":"The number of months in a year"},{"prompt":"Thirteen","expected":"thirteen","hint":"One more than twelve"},{"prompt":"Fifteen","expected":"fifteen","hint":"Halfway to twenty"},{"prompt":"Twenty","expected":"twenty","hint":"Two times ten"},{"prompt":"Twenty-one","expected":"twenty-one","hint":"One more than twenty"},{"prompt":"Twenty-five","expected":"twenty-five","hint":"Five times five"},{"prompt":"Thirty","expected":"thirty","hint":"Three times ten"}]}', 3),

('en', 'A1', 'speaking', 'Name the Colors', 'Say color names aloud',
'{"type":"speak_and_compare","instructions":"Look at the color and say its name.","exercises":[{"prompt":"Red 🔴","expected":"red","hint":"Color of fire"},{"prompt":"Blue 🔵","expected":"blue","hint":"Color of the ocean"},{"prompt":"Green 🟢","expected":"green","hint":"Color of leaves"},{"prompt":"Yellow 🟡","expected":"yellow","hint":"Color of bananas"},{"prompt":"Purple 🟣","expected":"purple","hint":"Mix of red and blue"},{"prompt":"Yellow 🟡","expected":"yellow","hint":"Color of the sun"},{"prompt":"Orange 🟠","expected":"orange","hint":"Color of a pumpkin"},{"prompt":"Purple 🟣","expected":"purple","hint":"Color of grapes"},{"prompt":"Pink 🌸","expected":"pink","hint":"Color of cotton candy"},{"prompt":"Brown 🟤","expected":"brown","hint":"Color of chocolate"},{"prompt":"Black ⬛","expected":"black","hint":"Color of night"},{"prompt":"White ⬜","expected":"white","hint":"Color of snow"},{"prompt":"Gray ⬜","expected":"gray","hint":"Color of ash"},{"prompt":"Teal 🟦","expected":"teal","hint":"Color of a peacock"},{"prompt":"Maroon 🟥","expected":"maroon","hint":"Color of wine"},{"prompt":"Cyan 🟦","expected":"cyan","hint":"Color of the sky on a clear day"},{"prompt":"Lavender 🟣","expected":"lavender","hint":"Color of lavender flowers"},{"prompt":"Magenta 🟣","expected":"magenta","hint":"Color of fuchsia"},{"prompt":"Gold 🟡","expected":"gold","hint":"Color of coins"},{"prompt":"Silver 🪙","expected":"silver","hint":"Color of jewelry"}]}', 4),

('en', 'A1', 'speaking', 'Animal Sounds', 'Say the names of animals',
'{"type":"speak_and_compare","instructions":"Say the animal name when you see it!","exercises":[{"prompt":"🐱 What animal is this?","expected":"cat","hint":"It says meow"},{"prompt":"🐶 What animal is this?","expected":"dog","hint":"It says woof"},{"prompt":"🐦 What animal is this?","expected":"bird","hint":"It can fly"},{"prompt":"🐟 What animal is this?","expected":"fish","hint":"It swims"},{"prompt":"🐘 What animal is this?","expected":"elephant","hint":"Very large with a trunk"},{"prompt":"🐘 What animal is this?","expected":"elephant","hint":"It has a trunk"},{"prompt":"🐴 What animal is this?","expected":"horse","hint":"It is often used for riding"},{"prompt":"🐍 What animal is this?","expected":"snake","hint":"It slithers on the ground"},{"prompt":"🐻 What animal is this?","expected":"bear","hint":"It likes honey"},{"prompt":"🐼 What animal is this?","expected":"panda","hint":"It eats bamboo"},{"prompt":"🦁 What animal is this?","expected":"lion","hint":"It is the king of the jungle"},{"prompt":"🐧 What animal is this?","expected":"penguin","hint":"It cannot fly but swims well"},{"prompt":"🐸 What animal is this?","expected":"frog","hint":"It jumps and says ribbit"},{"prompt":"🦋 What animal is this?","expected":"butterfly","hint":"It has colorful wings"},{"prompt":"🐥 What animal is this?","expected":"chick","hint":"It is a baby bird"},{"prompt":"🦊 What animal is this?","expected":"fox","hint":"It is known for being clever"},{"prompt":"🐴 What animal is this?","expected":"donkey","hint":"It is often used for carrying loads"},{"prompt":"🐢 What animal is this?","expected":"turtle","hint":"It has a hard shell"},{"prompt":"🐉 What animal is this?","expected":"dragon","hint":"It is a mythical creature"},{"prompt":"🦒 What animal is this?","expected":"giraffe","hint":"It has a long neck"}]}', 5);

