INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A1', 'reading', 'Match the Word', 'Read simple words and match to pictures',
'{"type":"read_and_match","instructions":"Read the word and choose the matching picture.","exercises":[{"word":"Cat","options":["🐱","🐶","🐟","🐦"],"correct":0},{"word":"Sun","options":["🌙","⭐","☀️","🌧️"],"correct":2},{"word":"Book","options":["📱","📖","🎮","🎸"],"correct":1},{"word":"Apple","options":["🍌","🍇","🍎","🍊"],"correct":2},{"word":"House","options":["🏫","🏠","🏥","🏪"],"correct":1},{"word":"Dog","options":["🐱","🐶","🐟","🐦"],"correct":1},{"word":"Tree","options":["🌳","🌵","🌻","🌼"],"correct":0},{"word":"Car","options":["🚗","🚲","🚌","🏍️"],"correct":0},{"word":"Fish","options":["🐟","🐠","🐡","🐬"],"correct":0},{"word":"Flower","options":["🌸","🌼","🌻","🌷"],"correct":0},{"word":"Moon","options":["🌙","☀️","⭐","🌌"],"correct":0},{"word":"House","options":["🏡","🏢","🏰","🏠"],"correct":0},{"word":"Ice Cream","options":["🍦","🍰","🍩","🍪"],"correct":0},{"word":"Bicycle","options":["🚴","🚲","🛴","🚗"],"correct":1},{"word":"Star","options":["⭐","🌟","🌙","☀️"],"correct":0},{"word":"Butterfly","options":["🦋","🐛","🌼","🌸"],"correct":0},{"word":"Pizza","options":["🍕","🍔","🌭","🥗"],"correct":0},{"word":"Laptop","options":["💻","📱","🖥️","🖨️"],"correct":0},{"word":"Camera","options":["📷","📸","📹","📼"],"correct":0},{"word":"Glasses","options":["🕶️","👓","👁️","🧑‍🏫"],"correct":1}]}', 1),

('en', 'A1', 'reading', 'Simple Sentences', 'Read short sentences and understand them',
'{"type":"read_and_choose","instructions":"Read the sentence and choose what it means.","exercises":[{"sentence":"The cat is on the mat.","question":"Where is the cat?","options":["On the mat","Under the table","In the box","On the bed"],"correct":0},{"sentence":"I have two apples.","question":"How many apples?","options":["One","Two","Three","Four"],"correct":1},{"sentence":"The sun is yellow.","question":"What color is the sun?","options":["Red","Blue","Yellow","Green"],"correct":2},{"sentence":"My dog is big.","question":"What is big?","options":["The cat","The bird","The fish","The dog"],"correct":3},{"sentence":"She likes ice cream.","question":"What does she like?","options":["Ice cream","Pizza","Cake","Bread"],"correct":0},{"sentence":"The dog is barking loudly.","question":"What is the dog doing?","options":["Sleeping","Barking loudly","Eating","Running"],"correct":1},{"sentence":"She is wearing a blue dress.","question":"What color is her dress?","options":["Red","Blue","Green","Yellow"],"correct":1},{"sentence":"They are playing soccer in the park.","question":"What game are they playing?","options":["Basketball","Soccer","Tennis","Baseball"],"correct":1},{"sentence":"He is reading a book quietly.","question":"What is he doing?","options":["Listening to music","Reading a book quietly","Talking loudly","Watching TV"],"correct":1},{"sentence":"The flowers are blooming.","question":"What are the flowers doing?","options":["Withering","Blooming","Fading","Growing"],"correct":1},{"sentence":"I enjoy eating ice cream.","question":"What do I enjoy?","options":["Eating cake","Eating ice cream","Drinking soda","Eating fruit"],"correct":1},{"sentence":"The sky is very cloudy today.","question":"What is the weather like today?","options":["Sunny","Cloudy","Rainy","Windy"],"correct":1},{"sentence":"She is an excellent singer.","question":"How is her singing?","options":["Bad","Average","Excellent","Poor"],"correct":2},{"sentence":"The baby is sleeping in the crib.","question":"Where is the baby?","options":["In the crib","On the floor","In the kitchen","In the car"],"correct":0},{"sentence":"We will go to the beach tomorrow.","question":"Where will we go tomorrow?","options":["To the mountains","To the city","To the beach","To the mall"],"correct":2},{"sentence":"He has a big smile on his face.","question":"What does he have on his face?","options":["A frown","A big smile","A tear","A scratch"],"correct":1},{"sentence":"The train arrives at 3 PM.","question":"What time does the train arrive?","options":["2 PM","3 PM","4 PM","5 PM"],"correct":1},{"sentence":"My favorite fruit is a banana.","question":"What is my favorite fruit?","options":["Apple","Banana","Orange","Grape"],"correct":1},{"sentence":"The movie starts at 7 o''clock.","question":"What time does the movie start?","options":["6 o''clock","7 o''clock","8 o''clock","9 o''clock"],"correct":1},{"sentence":"We had pizza for dinner last night.","question":"What did we have for dinner last night?","options":["Pasta","Salad","Pizza","Sushi"],"correct":2}]}', 2),

('en', 'A1', 'reading', 'Fill the Blank', 'Complete simple sentences',
'{"type":"fill_blank","instructions":"Read the sentence and choose the missing word.","exercises":[{"sentence":"The sky is ___.","options":["blue","big","fast","hot"],"correct":0},{"sentence":"I ___ a student.","options":["is","am","are","be"],"correct":1},{"sentence":"She ___ to school.","options":["go","goes","going","gone"],"correct":1},{"sentence":"We have ___ dogs.","options":["a","an","two","the"],"correct":2},{"sentence":"This is ___ apple.","options":["a","an","the","two"],"correct":1},{"sentence":"The cat is ___.","options":["soft","tall","quick","loud"],"correct":0},{"sentence":"They ___ playing soccer.","options":["is","am","are","be"],"correct":2},{"sentence":"He ___ a pizza.","options":["eat","eats","eating","eaten"],"correct":1},{"sentence":"We ___ to the park.","options":["go","goes","gone","going"],"correct":0},{"sentence":"The book is ___.","options":["interesting","interested","interest","interests"],"correct":0},{"sentence":"I ___ like chocolate.","options":["does","do","is","am"],"correct":1},{"sentence":"She ___ a beautiful dress.","options":["have","has","is","are"],"correct":1},{"sentence":"The dog is ___.","options":["happy","happiest","happily","happiness"],"correct":0},{"sentence":"You ___ to be quiet.","options":["need","needs","needing","needed"],"correct":0},{"sentence":"He ___ to the store yesterday.","options":["go","went","going","gone"],"correct":1},{"sentence":"They ___ happy about the news.","options":["is","are","was","were"],"correct":1},{"sentence":"The flowers are ___.","options":["pretty","prettily","prettiest","prettiness"],"correct":0},{"sentence":"I ___ my homework.","options":["finish","finishes","finished","finishing"],"correct":2},{"sentence":"She ___ a great singer.","options":["be","is","are","was"],"correct":1},{"sentence":"We ___ going to the concert.","options":["is","am","are","be"],"correct":2}]}', 3),

('en', 'A1', 'reading', 'True or False', 'Read and decide if statements are true',
'{"type":"true_false","instructions":"Read the sentence. Is it TRUE or FALSE?","exercises":[{"statement":"A cat can fly.","correct":false,"explanation":"Cats cannot fly. Birds can fly!"},{"statement":"The sun is hot.","correct":true,"explanation":"Yes! The sun is very hot."},{"statement":"Fish live in water.","correct":true,"explanation":"Correct! Fish live in water."},{"statement":"Ice cream is hot.","correct":false,"explanation":"No! Ice cream is cold and yummy."},{"statement":"People have two eyes.","correct":true,"explanation":"Yes! We have two eyes."},{"statement":"Dogs are mammals.","correct":true,"explanation":"Correct! Dogs belong to the mammal class."},{"statement":"A fish can walk on land.","correct":false,"explanation":"Fish cannot walk on land; they are aquatic animals."},{"statement":"The Earth orbits the Sun.","correct":true,"explanation":"Yes! The Earth revolves around the Sun in a path called an orbit."},{"statement":"All birds can swim.","correct":false,"explanation":"Not all birds can swim. Some birds, like penguins, can swim, but others cannot."},{"statement":"Humans need water to survive.","correct":true,"explanation":"Correct! Water is essential for human life."},{"statement":"A butterfly is a type of insect.","correct":true,"explanation":"Yes! Butterflies are classified as insects."},{"statement":"Trees can grow in deserts.","correct":false,"explanation":"Most trees cannot grow in deserts due to lack of water."},{"statement":"The ocean is made of fresh water.","correct":false,"explanation":"The ocean is primarily made of salt water, not fresh water."},{"statement":"Snakes have legs.","correct":false,"explanation":"Snakes do not have legs; they move by slithering."},{"statement":"The moon is a natural satellite of Earth.","correct":true,"explanation":"Yes! The moon orbits around the Earth as its natural satellite."},{"statement":"Elephants are the largest land animals.","correct":true,"explanation":"Correct! Elephants are the largest animals that live on land."},{"statement":"Bats are birds.","correct":false,"explanation":"Bats are mammals, not birds; they can fly but are classified differently."},{"statement":"Rain is a form of precipitation.","correct":true,"explanation":"Yes! Rain is one type of precipitation that falls from the atmosphere."},{"statement":"All plants can produce flowers.","correct":false,"explanation":"Not all plants produce flowers; some reproduce through spores."},{"statement":"The Arctic is known for being very cold.","correct":true,"explanation":"Correct! The Arctic region is characterized by its cold climate."}]}', 4),

('en', 'A1', 'reading', 'Word Families', 'Group related words together',
'{"type":"read_and_match","instructions":"Read the word and choose which group it belongs to.","exercises":[{"word":"Dog","options":["Animals","Foods","Colors","Numbers"],"correct":0},{"word":"Red","options":["Animals","Foods","Colors","Numbers"],"correct":2},{"word":"Apple","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Three","options":["Animals","Foods","Colors","Numbers"],"correct":3},{"word":"Banana","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Cat","options":["Animals","Foods","Colors","Numbers"],"correct":0},{"word":"Banana","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Blue","options":["Animals","Foods","Colors","Numbers"],"correct":2},{"word":"Three","options":["Animals","Foods","Colors","Numbers"],"correct":3},{"word":"Elephant","options":["Animals","Foods","Colors","Numbers"],"correct":0},{"word":"Carrot","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Green","options":["Animals","Foods","Colors","Numbers"],"correct":2},{"word":"Five","options":["Animals","Foods","Colors","Numbers"],"correct":3},{"word":"Lion","options":["Animals","Foods","Colors","Numbers"],"correct":0},{"word":"Pizza","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Yellow","options":["Animals","Foods","Colors","Numbers"],"correct":2},{"word":"One","options":["Animals","Foods","Colors","Numbers"],"correct":3},{"word":"Giraffe","options":["Animals","Foods","Colors","Numbers"],"correct":0},{"word":"Chicken","options":["Animals","Foods","Colors","Numbers"],"correct":1},{"word":"Purple","options":["Animals","Foods","Colors","Numbers"],"correct":2}]}', 5);

