-- A1 WRITING LESSONS
-- ============================================================
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A1', 'writing', 'Type the Letters', 'Practice typing individual letters',
'{"type":"type_word","instructions":"Type the letter you see on screen.","exercises":[{"prompt":"Type the letter: A","expected":"A","hint":"The first letter of the alphabet"},{"prompt":"Type the letter: B","expected":"B","hint":"The second letter"},{"prompt":"Type the letter: C","expected":"C","hint":"Cat starts with this letter"},{"prompt":"Type the letter: D","expected":"D","hint":"Dog starts with this letter"},{"prompt":"Type the letter: E","expected":"E","hint":"Elephant starts with this letter"},{"prompt":"Type the letter: D","expected":"D","hint":"The fourth letter of the alphabet"},{"prompt":"Type the letter: E","expected":"E","hint":"The fifth letter, often used in ''elephant''"},{"prompt":"Type the letter: F","expected":"F","hint":"The letter that starts ''fish''"},{"prompt":"Type the letter: G","expected":"G","hint":"The letter that starts ''giraffe''"},{"prompt":"Type the letter: H","expected":"H","hint":"The eighth letter, like in ''hat''"},{"prompt":"Type the letter: I","expected":"I","hint":"The letter that begins ''igloo''"},{"prompt":"Type the letter: J","expected":"J","hint":"The letter that starts ''jacket''"},{"prompt":"Type the letter: K","expected":"K","hint":"The letter that starts ''kangaroo''"},{"prompt":"Type the letter: L","expected":"L","hint":"The twelfth letter, often seen in ''lemon''"},{"prompt":"Type the letter: M","expected":"M","hint":"The letter that starts ''monkey''"},{"prompt":"Type the letter: N","expected":"N","hint":"The letter that begins ''nose''"},{"prompt":"Type the letter: O","expected":"O","hint":"The fifteenth letter, like in ''octopus''"},{"prompt":"Type the letter: P","expected":"P","hint":"The letter that starts ''panda''"},{"prompt":"Type the letter: Q","expected":"Q","hint":"The letter that starts ''queen''"},{"prompt":"Type the letter: R","expected":"R","hint":"The letter that begins ''rabbit''"}]}', 1),

('en', 'A1', 'writing', 'Spell Simple Words', 'Type short words correctly',
'{"type":"type_word","instructions":"Listen to the word and type it correctly.","exercises":[{"prompt":"cat","expected":"cat","hint":"🐱 Three letters, starts with C"},{"prompt":"dog","expected":"dog","hint":"🐶 Three letters, starts with D"},{"prompt":"sun","expected":"sun","hint":"☀️ Three letters, starts with S"},{"prompt":"red","expected":"red","hint":"🔴 Three letters, a color"},{"prompt":"big","expected":"big","hint":"The opposite of small"},{"prompt":"fish","expected":"fish","hint":"🐟 Four letters, starts with F"},{"prompt":"frog","expected":"frog","hint":"🐸 Four letters, starts with F"},{"prompt":"tree","expected":"tree","hint":"🌳 Four letters, starts with T"},{"prompt":"star","expected":"star","hint":"⭐ Four letters, starts with S"},{"prompt":"ball","expected":"ball","hint":"⚽ Four letters, starts with B"},{"prompt":"cake","expected":"cake","hint":"🍰 Four letters, starts with C"},{"prompt":"bird","expected":"bird","hint":"🐦 Four letters, starts with B"},{"prompt":"hand","expected":"hand","hint":"✋ Four letters, starts with H"},{"prompt":"milk","expected":"milk","hint":"🥛 Four letters, starts with M"},{"prompt":"shoe","expected":"shoe","hint":"👟 Four letters, starts with S"},{"prompt":"book","expected":"book","hint":"📚 Four letters, starts with B"},{"prompt":"lamp","expected":"lamp","hint":"💡 Four letters, starts with L"},{"prompt":"coat","expected":"coat","hint":"🧥 Four letters, starts with C"},{"prompt":"door","expected":"door","hint":"🚪 Four letters, starts with D"},{"prompt":"rain","expected":"rain","hint":"☔ Four letters, starts with R"}]}', 2),

('en', 'A1', 'writing', 'Unscramble Words', 'Rearrange letters to make words',
'{"type":"unscramble","instructions":"The letters are mixed up! Type the correct word.","exercises":[{"scrambled":"tac","expected":"cat","hint":"🐱 A pet that says meow"},{"scrambled":"nus","expected":"sun","hint":"☀️ It shines in the sky"},{"scrambled":"ppalpe","expected":"apple","hint":"🍎 A red fruit"},{"scrambled":"okbo","expected":"book","hint":"📖 You read this"},{"scrambled":"ishf","expected":"fish","hint":"🐟 It swims in water"},{"scrambled":"ogd","expected":"dog","hint":"🐶 A common pet that barks"},{"scrambled":"rteab","expected":"bread","hint":"🍞 A staple food made from flour"},{"scrambled":"rainsg","expected":"saring","hint":"🌧️ Water that falls from the sky"},{"scrambled":"aolc","expected":"coal","hint":"🪨 A black rock used for fuel"},{"scrambled":"nletye","expected":"letyne","hint":"🎵 A musical instrument with keys"},{"scrambled":"peelr","expected":"pearl","hint":"💎 A precious gem found in oysters"},{"scrambled":"htrae","expected":"earth","hint":"🌍 The planet we live on"},{"scrambled":"sytne","expected":"scent","hint":"🌸 A pleasant smell"},{"scrambled":"unreif","expected":"unfire","hint":"🔥 A destructive force that consumes"},{"scrambled":"btrieh","expected":"birth","hint":"👶 The beginning of life"},{"scrambled":"pnlta","expected":"plant","hint":"🌱 A living organism that grows in soil"},{"scrambled":"pafl","expected":"flap","hint":"🕊️ The motion of wings"},{"scrambled":"onacb","expected":"banco","hint":"🏦 A place to keep money"},{"scrambled":"sacir","expected":"acris","hint":"🎨 A form of creative expression"},{"scrambled":"tneelg","expected":"gentle","hint":"🌼 Soft and mild in action"}]}', 3),

('en', 'A1', 'writing', 'Complete the Word', 'Fill in missing letters',
'{"type":"fill_letters","instructions":"Some letters are missing. Type the complete word.","exercises":[{"partial":"c_t","expected":"cat","hint":"🐱 A furry pet"},{"partial":"d_g","expected":"dog","hint":"🐶 A loyal pet"},{"partial":"b__k","expected":"book","hint":"📖 You read it"},{"partial":"h__se","expected":"house","hint":"🏠 Where you live"},{"partial":"fl__er","expected":"flower","hint":"🌸 Grows in a garden"},{"partial":"c__k","expected":"cake","hint":"🍰 A sweet dessert"},{"partial":"f__d","expected":"food","hint":"🍽️ What we eat"},{"partial":"s__p","expected":"soap","hint":"🧼 Used for washing"},{"partial":"b__l","expected":"ball","hint":"⚽ A round object for games"},{"partial":"t__e","expected":"tree","hint":"🌳 A tall plant"},{"partial":"s__m","expected":"swim","hint":"🏊 An activity in water"},{"partial":"p__n","expected":"pen","hint":"🖊️ Used for writing"},{"partial":"h__p","expected":"hope","hint":"🌟 A feeling of expectation"},{"partial":"g__l","expected":"goal","hint":"🏆 What you aim to achieve"},{"partial":"l__g","expected":"log","hint":"🌲 A piece of wood"},{"partial":"w__r","expected":"wear","hint":"👗 To put on clothing"},{"partial":"t__p","expected":"tape","hint":"📼 Used for sticking things together"},{"partial":"m__n","expected":"moon","hint":"🌕 A celestial body at night"},{"partial":"c__r","expected":"car","hint":"🚗 A vehicle for transportation"},{"partial":"j__g","expected":"jog","hint":"🏃‍♂️ A form of running"}]}', 4),

('en', 'A1', 'writing', 'Write a Sentence', 'Copy simple sentences by typing',
'{"type":"copy_sentence","instructions":"Read the sentence and type it exactly as shown.","exercises":[{"sentence":"I am happy.","expected":"I am happy.","hint":"Three words and a period"},{"sentence":"The cat is big.","expected":"The cat is big.","hint":"Four words about a cat"},{"sentence":"I like red.","expected":"I like red.","hint":"Three words about a color"},{"sentence":"She has a dog.","expected":"She has a dog.","hint":"Four words about a pet"},{"sentence":"We go to school.","expected":"We go to school.","hint":"Four words about where you learn"},{"sentence":"The dog is playful.","expected":"The dog is playful.","hint":"Four words about a dog"},{"sentence":"She loves ice cream.","expected":"She loves ice cream.","hint":"Four words about a treat"},{"sentence":"They are my friends.","expected":"They are my friends.","hint":"Four words about friendship"},{"sentence":"He plays the guitar.","expected":"He plays the guitar.","hint":"Four words about music"},{"sentence":"The sky is blue.","expected":"The sky is blue.","hint":"Four words about the sky"},{"sentence":"We enjoy summer days.","expected":"We enjoy summer days.","hint":"Five words about a season"},{"sentence":"Birds sing in the morning.","expected":"Birds sing in the morning.","hint":"Five words about birds"},{"sentence":"He reads many books.","expected":"He reads many books.","hint":"Four words about reading"},{"sentence":"I love to travel.","expected":"I love to travel.","hint":"Four words about exploration"},{"sentence":"She dances with joy.","expected":"She dances with joy.","hint":"Four words about dancing"},{"sentence":"The flowers are beautiful.","expected":"The flowers are beautiful.","hint":"Five words about flowers"},{"sentence":"They play in the park.","expected":"They play in the park.","hint":"Five words about playing"},{"sentence":"I enjoy rainy nights.","expected":"I enjoy rainy nights.","hint":"Four words about weather"},{"sentence":"The cake is delicious.","expected":"The cake is delicious.","hint":"Four words about dessert"},{"sentence":"We watch the sunset.","expected":"We watch the sunset.","hint":"Four words about evening"}]}', 5);

-- ============================================================
-- A2 LISTENING LESSONS
-- ============================================================
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A2', 'listening', 'My Daily Routine', 'Listen to descriptions of daily activities',
'{"type":"listen_and_choose","instructions":"Listen to the sentence and answer the question.","exercises":[{"prompt":"I wake up at seven o''clock every morning.","question":"What time does the person wake up?","options":["6 o''clock","7 o''clock","8 o''clock","9 o''clock"],"correct":1},{"prompt":"After breakfast, I brush my teeth and go to school.","question":"What happens after breakfast?","options":["Sleep","Play games","Brush teeth and go to school","Watch TV"],"correct":2},{"prompt":"I have lunch at twelve thirty.","question":"When is lunch?","options":["11:00","12:00","12:30","1:00"],"correct":2},{"prompt":"In the evening, I do my homework.","question":"When does homework happen?","options":["Morning","Afternoon","Evening","Night"],"correct":2},{"prompt":"I go to bed at nine o''clock.","question":"What is the bedtime?","options":["8 PM","9 PM","10 PM","11 PM"],"correct":1},{"prompt":"I usually go for a run at six in the evening.","question":"What time does the person go for a run?","options":["5 o''clock","6 o''clock","7 o''clock","8 o''clock"],"correct":1},{"prompt":"On weekends, I like to read books in the afternoon.","question":"What does the person like to do on weekends?","options":["Watch movies","Read books","Go shopping","Play sports"],"correct":1},{"prompt":"I take a shower before going to bed.","question":"When does the person take a shower?","options":["In the morning","Before dinner","Before going to bed","After lunch"],"correct":2},{"prompt":"I eat dinner at seven o''clock in the evening.","question":"What time is dinner?","options":["6 o''clock","7 o''clock","8 o''clock","9 o''clock"],"correct":1},{"prompt":"Every Sunday, I visit my grandparents.","question":"When does the person visit their grandparents?","options":["Every day","Every Saturday","Every Sunday","Every month"],"correct":2},{"prompt":"I always drink coffee in the morning.","question":"When does the person drink coffee?","options":["In the afternoon","In the evening","In the morning","At night"],"correct":2},{"prompt":"After school, I do my homework.","question":"What does the person do after school?","options":["Play with friends","Watch TV","Do homework","Go shopping"],"correct":2},{"prompt":"I like to cook dinner on Friday nights.","question":"When does the person like to cook dinner?","options":["Monday nights","Wednesday nights","Friday nights","Saturday nights"],"correct":2},{"prompt":"I go to bed at ten o''clock.","question":"What time does the person go to bed?","options":["9 o''clock","10 o''clock","11 o''clock","12 o''clock"],"correct":1},{"prompt":"I enjoy listening to music while studying.","question":"What does the person enjoy while studying?","options":["Talking","Listening to music","Watching TV","Playing games"],"correct":1},{"prompt":"I usually have a snack in the afternoon.","question":"When does the person usually have a snack?","options":["In the morning","In the afternoon","In the evening","At night"],"correct":1},{"prompt":"On rainy days, I prefer to stay indoors.","question":"What does the person prefer on rainy days?","options":["Go outside","Stay indoors","Visit friends","Go to the park"],"correct":1},{"prompt":"I like to ride my bike on sunny days.","question":"When does the person like to ride their bike?","options":["On rainy days","On snowy days","On sunny days","At night"],"correct":2},{"prompt":"I watch the news every evening at eight.","question":"What time does the person watch the news?","options":["6 o''clock","7 o''clock","8 o''clock","9 o''clock"],"correct":2},{"prompt":"I like to eat breakfast at eight thirty.","question":"When does the person eat breakfast?","options":["7:00","8:00","8:30","9:00"],"correct":2}]}', 1),

('en', 'A2', 'listening', 'At the Shop', 'Listen to shopping dialogues',
'{"type":"listen_and_choose","instructions":"Listen to the conversation and answer.","exercises":[{"prompt":"Can I have two apples, please? That will be one dollar.","question":"How much do the apples cost?","options":["Two dollars","One dollar","Three dollars","Five dollars"],"correct":1},{"prompt":"Do you have any milk? Yes, it is in the fridge.","question":"Where is the milk?","options":["On the shelf","In the fridge","On the table","In the bag"],"correct":1},{"prompt":"I would like a sandwich and some juice, please.","question":"What does the person want?","options":["Pizza and water","Sandwich and juice","Cake and tea","Burger and cola"],"correct":1},{"prompt":"How much is this book? It costs five dollars.","question":"How much is the book?","options":["Three dollars","Four dollars","Five dollars","Six dollars"],"correct":2},{"prompt":"Thank you for shopping with us. Have a nice day!","question":"What does the shopkeeper say?","options":["Come back tomorrow","Have a nice day","The shop is closed","Goodbye forever"],"correct":1},{"prompt":"Can I get a cup of coffee? Sure, that will be three dollars.","question":"How much does the coffee cost?","options":["Two dollars","Three dollars","Four dollars","Five dollars"],"correct":1},{"prompt":"Where is the nearest bank? It''s just around the corner.","question":"Where is the bank?","options":["Next to the grocery store","Around the corner","In the mall","On the main street"],"correct":1},{"prompt":"I need a dozen eggs and a carton of milk.","question":"What does the person need?","options":["A loaf of bread and butter","A dozen eggs and milk","Some cheese and ham","A bag of flour and sugar"],"correct":1},{"prompt":"Can you help me with my homework? Yes, I can help you.","question":"What does the person need help with?","options":["Shopping","Cooking","Homework","Cleaning"],"correct":2},{"prompt":"What time does the movie start? It starts at 7 PM.","question":"When does the movie start?","options":["At 5 PM","At 6 PM","At 7 PM","At 8 PM"],"correct":2},{"prompt":"Can I borrow your pen? Sure, here it is.","question":"What does the person want to borrow?","options":["A pencil","A book","A pen","A ruler"],"correct":2},{"prompt":"Do you have a map? Yes, it''s in my bag.","question":"Where is the map?","options":["On the table","In my bag","In the car","At home"],"correct":1},{"prompt":"I would like to order a pizza, please.","question":"What does the person want to order?","options":["A salad","A sandwich","A pizza","A drink"],"correct":2},{"prompt":"Is there a restroom nearby? Yes, it''s down the hall.","question":"Where is the restroom?","options":["In the kitchen","Down the hall","In the basement","On the roof"],"correct":1},{"prompt":"Would you like some tea? Yes, I would love some.","question":"What does the person want?","options":["Coffee","Juice","Tea","Water"],"correct":2},{"prompt":"Can you pass the salt, please? Of course, here you go.","question":"What does the person want passed?","options":["Pepper","Salt","Sugar","Oil"],"correct":1},{"prompt":"What is your favorite color? I love blue.","question":"What is the person''s favorite color?","options":["Red","Green","Blue","Yellow"],"correct":2},{"prompt":"Can I see the menu? Yes, here it is.","question":"What does the person want to see?","options":["The bill","The menu","The drink list","The specials"],"correct":1},{"prompt":"Do you want to go for a walk? Yes, that sounds nice.","question":"What does the person want to do?","options":["Go for a swim","Go for a walk","Stay at home","Go shopping"],"correct":1},{"prompt":"Can I get a large coffee and a muffin, please?","question":"What does the person want?","options":["Tea and a cookie","Large coffee and muffin","Small coffee and croissant","Juice and a sandwich"],"correct":1}]}', 2),

('en', 'A2', 'listening', 'Weather Report', 'Listen to weather descriptions',
'{"type":"listen_and_choose","instructions":"Listen to the weather report and answer.","exercises":[{"prompt":"Today will be sunny and warm. The temperature is 25 degrees.","question":"What is the weather like?","options":["Rainy","Sunny and warm","Cold and snowy","Windy"],"correct":1},{"prompt":"It is raining outside. Don''t forget your umbrella!","question":"What should you bring?","options":["Sunglasses","An umbrella","A hat","Gloves"],"correct":1},{"prompt":"Tomorrow will be cloudy with a chance of rain.","question":"What will tomorrow be like?","options":["Sunny","Snowy","Cloudy with rain","Hot"],"correct":2},{"prompt":"In winter, it is very cold and it sometimes snows.","question":"What happens in winter?","options":["It is hot","It is cold and snowy","It is rainy","It is windy"],"correct":1},{"prompt":"The wind is strong today. Hold onto your hat!","question":"What is strong today?","options":["The rain","The sun","The wind","The snow"],"correct":2},{"prompt":"The forecast says it will be windy and chilly today, with temperatures around 15 degrees.","question":"What is the weather like today?","options":["Hot and humid","Windy and chilly","Clear and warm","Foggy"],"correct":1},{"prompt":"There is a snowstorm expected tomorrow. Stay safe and warm indoors!","question":"What should you do tomorrow?","options":["Go for a walk","Stay indoors","Have a picnic","Ride a bike"],"correct":1},{"prompt":"It will be partly cloudy with a high of 20 degrees this weekend.","question":"What will the temperature be this weekend?","options":["10 degrees","20 degrees","30 degrees","15 degrees"],"correct":1},{"prompt":"Expect thunderstorms this afternoon. Be careful if you''re driving.","question":"What is expected this afternoon?","options":["Thunderstorms","Clear skies","Heavy rain","Fog"],"correct":0},{"prompt":"The weather will be perfect for a beach day, sunny with a temperature of 30 degrees.","question":"What is the temperature for the beach day?","options":["25 degrees","30 degrees","35 degrees","20 degrees"],"correct":1},{"prompt":"Today is expected to be overcast with a chance of light drizzle in the evening.","question":"What will happen in the evening?","options":["It will be sunny","There may be light drizzle","It will snow","It will be foggy"],"correct":1},{"prompt":"The temperature is dropping, and it might snow tonight. Dress warmly!","question":"What should you wear tonight?","options":["Shorts","A warm jacket","Flip-flops","A light sweater"],"correct":1},{"prompt":"Tomorrow will be a scorcher, reaching 35 degrees. Stay hydrated!","question":"What should you remember to do tomorrow?","options":["Stay hydrated","Wear a winter coat","Bring a snow shovel","Stay indoors"],"correct":0},{"prompt":"Expect mild temperatures with occasional rain throughout the day.","question":"What type of weather is expected?","options":["Mild with occasional rain","Hot and dry","Cold and snowy","Windy and sunny"],"correct":0},{"prompt":"It will be a lovely day for a hike, with temperatures around 22 degrees and sunny.","question":"What is the weather like for a hike?","options":["Rainy and cold","Sunny and 22 degrees","Snowy and icy","Windy and warm"],"correct":1},{"prompt":"This evening will be cool and calm, perfect for a stroll outside.","question":"What is the weather like this evening?","options":["Cool and calm","Hot and humid","Stormy","Very windy"],"correct":0},{"prompt":"Prepare for a chilly morning with frost on the ground. Wear warm clothes!","question":"What should you wear in the morning?","options":["Warm clothes","A swimsuit","Sandals","Shorts"],"correct":0},{"prompt":"Tomorrow will be partly sunny with a high of 28 degrees.","question":"What is the expected high temperature tomorrow?","options":["18 degrees","28 degrees","38 degrees","22 degrees"],"correct":1},{"prompt":"We are expecting heavy rain this weekend, so plan indoor activities.","question":"What should you plan for the weekend?","options":["Outdoor activities","Indoor activities","A beach trip","A picnic"],"correct":1},{"prompt":"The forecast shows snow in the evening with temperatures dropping to minus 5 degrees.","question":"What will the weather be like in the evening?","options":["Clear skies","Snowy and cold","Warm and sunny","Foggy"],"correct":1}]}', 3),

('en', 'A2', 'listening', 'Asking for Directions', 'Listen to direction conversations',
'{"type":"listen_and_choose","instructions":"Listen and answer the question about directions.","exercises":[{"prompt":"Excuse me, where is the library? Go straight and turn left.","question":"How do you get to the library?","options":["Turn right","Go straight and turn left","Go back","Turn around"],"correct":1},{"prompt":"The school is next to the park.","question":"Where is the school?","options":["Far from the park","Next to the park","Behind the park","In front of the park"],"correct":1},{"prompt":"Walk for five minutes and you will see the hospital on your right.","question":"Where is the hospital?","options":["On the left","On the right","Behind you","Very far away"],"correct":1},{"prompt":"The supermarket is between the bank and the post office.","question":"Where is the supermarket?","options":["Next to the school","Behind the bank","Between bank and post office","Far away"],"correct":2},{"prompt":"Cross the street and the bus stop is right there.","question":"What should you do?","options":["Turn left","Go back home","Cross the street","Take a taxi"],"correct":2},{"prompt":"Turn right at the traffic light and the bank will be on your left.","question":"Where is the bank?","options":["On the left","On the right","Straight ahead","Next to the supermarket"],"correct":0},{"prompt":"The post office is across from the gas station.","question":"Where is the post office?","options":["Next to the gas station","Behind the gas station","Across from the gas station","In front of the gas station"],"correct":2},{"prompt":"Go down this street and take the first right; the restaurant is on your left.","question":"Where is the restaurant?","options":["On the left","On the right","In front of you","Behind you"],"correct":0},{"prompt":"The grocery store is two blocks away, just past the bakery.","question":"How far is the grocery store?","options":["One block away","Two blocks away","Three blocks away","At the next corner"],"correct":1},{"prompt":"To get to the museum, go straight for three minutes until you see it on your right.","question":"Where is the museum?","options":["On the left","In front of you","On your right","Behind you"],"correct":2},{"prompt":"The cinema is next to the library and across from the coffee shop.","question":"Where is the cinema located?","options":["Next to the library","Across from the coffee shop","Both A and B","Behind the library"],"correct":2},{"prompt":"Walk past the park and you will find the playground on your right.","question":"Where is the playground?","options":["On the left","On the right","In front of the park","Next to the park"],"correct":1},{"prompt":"The train station is just down the road after the bridge.","question":"Where is the train station?","options":["Before the bridge","After the bridge","Next to the bus stop","Across the street"],"correct":1},{"prompt":"To find the pharmacy, go straight and look for the sign on your left.","question":"Where is the pharmacy located?","options":["On the left","On the right","At the corner","Behind you"],"correct":0},{"prompt":"The beach is a short walk from the hotel, just follow the signs.","question":"How far is the beach from the hotel?","options":["A short walk","A long drive","Next door","Across the street"],"correct":0},{"prompt":"Drive straight until you see the mall on your left.","question":"Where is the mall?","options":["On the right","On the left","Behind you","In front of you"],"correct":1},{"prompt":"The zoo is located at the end of this street, next to the river.","question":"Where is the zoo?","options":["At the end of this street","At the beginning of this street","Next to the park","Behind the city hall"],"correct":0},{"prompt":"You will find the art gallery on the third floor of the building.","question":"Where is the art gallery?","options":["On the second floor","On the first floor","On the third floor","On the roof"],"correct":2},{"prompt":"To reach the office, go up the stairs and turn left.","question":"How do you get to the office?","options":["Go up the stairs and turn right","Go up the stairs and turn left","Take the elevator","Walk straight ahead"],"correct":1},{"prompt":"The university is a ten-minute walk from the bus station.","question":"How long will it take to walk to the university?","options":["Five minutes","Ten minutes","Fifteen minutes","Twenty minutes"],"correct":1}]}', 4);

