INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A2', 'speaking', 'Describe Your Day', 'Talk about daily routines',
'{"type":"speak_and_compare","instructions":"Say each sentence clearly. We will check your words!","exercises":[{"prompt":"I wake up early in the morning.","expected":"i wake up early in the morning","hint":"Start of your day"},{"prompt":"I eat breakfast at eight o''clock.","expected":"i eat breakfast at eight o clock","hint":"Your first meal"},{"prompt":"I go to school by bus.","expected":"i go to school by bus","hint":"How you travel"},{"prompt":"I play with my friends after school.","expected":"i play with my friends after school","hint":"After classes finish"},{"prompt":"I read a book before bed.","expected":"i read a book before bed","hint":"Something you do at night"},{"prompt":"I read a book every night.","expected":"i read a book every night","hint":"A bedtime activity"},{"prompt":"I play soccer with my friends.","expected":"i play soccer with my friends","hint":"A weekend sport"},{"prompt":"I study math after school.","expected":"i study math after school","hint":"Learning time"},{"prompt":"I help my parents with chores.","expected":"i help my parents with chores","hint":"Family responsibilities"},{"prompt":"I watch movies on weekends.","expected":"i watch movies on weekends","hint":"Free time activity"},{"prompt":"I visit my grandparents every month.","expected":"i visit my grandparents every month","hint":"Family visits"},{"prompt":"I go for a walk in the park.","expected":"i go for a walk in the park","hint":"Outdoor activity"},{"prompt":"I enjoy cooking new recipes.","expected":"i enjoy cooking new recipes","hint":"In the kitchen"},{"prompt":"I play video games in my free time.","expected":"i play video games in my free time","hint":"Digital fun"},{"prompt":"I drink water throughout the day.","expected":"i drink water throughout the day","hint":"Stay hydrated"},{"prompt":"I write in my journal daily.","expected":"i write in my journal daily","hint":"Personal reflection"},{"prompt":"I take photos when I travel.","expected":"i take photos when i travel","hint":"Capture memories"},{"prompt":"I listen to music while studying.","expected":"i listen to music while studying","hint":"Background sound"},{"prompt":"I practice speaking English regularly.","expected":"i practice speaking english regularly","hint":"Language improvement"},{"prompt":"I attend classes every weekday.","expected":"i attend classes every weekday","hint":"School schedule"}]}', 1),

('en', 'A2', 'speaking', 'At the Restaurant', 'Practice ordering food',
'{"type":"speak_and_compare","instructions":"Pretend you are at a restaurant. Say each sentence.","exercises":[{"prompt":"Can I see the menu, please?","expected":"can i see the menu please","hint":"Asking for the menu"},{"prompt":"I would like a pizza, please.","expected":"i would like a pizza please","hint":"Ordering food"},{"prompt":"Can I have some water?","expected":"can i have some water","hint":"Ordering a drink"},{"prompt":"How much does it cost?","expected":"how much does it cost","hint":"Asking about the price"},{"prompt":"Thank you, the food was delicious!","expected":"thank you the food was delicious","hint":"Complimenting the meal"},{"prompt":"Could I get the bill, please?","expected":"could i get the bill please","hint":"Requesting the check"},{"prompt":"What are today’s specials?","expected":"what are todays specials","hint":"Inquiring about specials"},{"prompt":"I’ll have the steak, medium rare.","expected":"ill have the steak medium rare","hint":"Ordering a specific dish"},{"prompt":"Could you recommend a dessert?","expected":"could you recommend a dessert","hint":"Asking for dessert suggestions"},{"prompt":"Is there a vegetarian option?","expected":"is there a vegetarian option","hint":"Inquiring about dietary options"},{"prompt":"Do you have any gluten-free dishes?","expected":"do you have any gluten free dishes","hint":"Asking about gluten-free options"},{"prompt":"Can I get this to go?","expected":"can i get this to go","hint":"Requesting takeout"},{"prompt":"Could I have extra napkins, please?","expected":"could i have extra napkins please","hint":"Requesting more napkins"},{"prompt":"What time do you close?","expected":"what time do you close","hint":"Asking about closing time"},{"prompt":"Can we have a table by the window?","expected":"can we have a table by the window","hint":"Requesting a specific seating"},{"prompt":"I’m allergic to nuts.","expected":"im allergic to nuts","hint":"Informing about allergies"},{"prompt":"Can I order the soup of the day?","expected":"can i order the soup of the day","hint":"Ordering a specific item"},{"prompt":"Do you accept credit cards?","expected":"do you accept credit cards","hint":"Inquiring about payment methods"},{"prompt":"Can I have this dish without onions?","expected":"can i have this dish without onions","hint":"Requesting a modification"},{"prompt":"Is service included in the bill?","expected":"is service included in the bill","hint":"Asking about service charge"}]}', 2),

('en', 'A2', 'speaking', 'Tell a Short Story', 'Describe a sequence of events',
'{"type":"speak_and_compare","instructions":"Read the story prompt and say the sentence out loud.","exercises":[{"prompt":"Yesterday, I went to the park.","expected":"yesterday i went to the park","hint":"Past tense of go"},{"prompt":"I saw a big brown dog there.","expected":"i saw a big brown dog there","hint":"Describing what you saw"},{"prompt":"The dog was playing with a ball.","expected":"the dog was playing with a ball","hint":"What was the dog doing?"},{"prompt":"I wanted to play with the dog.","expected":"i wanted to play with the dog","hint":"What you wanted"},{"prompt":"It was a wonderful day!","expected":"it was a wonderful day","hint":"How the day was"},{"prompt":"I had a picnic with my friends.","expected":"i had a picnic with my friends","hint":"Past tense of have"},{"prompt":"We enjoyed delicious sandwiches.","expected":"we enjoyed delicious sandwiches","hint":"What did you eat?"},{"prompt":"The sun was shining brightly.","expected":"the sun was shining brightly","hint":"Describe the weather"},{"prompt":"We played frisbee in the field.","expected":"we played frisbee in the field","hint":"What game did you play?"},{"prompt":"Later, we took funny pictures.","expected":"later we took funny pictures","hint":"What did you do after?"},{"prompt":"Everyone laughed and had fun.","expected":"everyone laughed and had fun","hint":"What was the mood like?"},{"prompt":"I packed my favorite snacks.","expected":"i packed my favorite snacks","hint":"What did you bring?"},{"prompt":"We sat under a big tree.","expected":"we sat under a big tree","hint":"Where did you sit?"},{"prompt":"The birds were singing sweetly.","expected":"the birds were singing sweetly","hint":"What were the birds doing?"},{"prompt":"It was a perfect day for a picnic.","expected":"it was a perfect day for a picnic","hint":"How was the day?"},{"prompt":"My friend brought a guitar.","expected":"my friend brought a guitar","hint":"What musical instrument was there?"},{"prompt":"We listened to music and danced.","expected":"we listened to music and danced","hint":"What did you do with the guitar?"},{"prompt":"At sunset, we packed our things.","expected":"at sunset we packed our things","hint":"What did you do at the end?"},{"prompt":"I felt happy and relaxed.","expected":"i felt happy and relaxed","hint":"How did you feel?"},{"prompt":"We promised to do it again.","expected":"we promised to do it again","hint":"What did you say about future picnics?"}]}', 3);

-- ============================================================
-- A2 READING LESSONS
-- ============================================================
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A2', 'reading', 'A Short Story', 'Read and understand a simple story',
'{"type":"read_and_choose","instructions":"Read the story and answer the questions.","passage":"Tom gets up at seven o''clock. He eats toast and drinks orange juice for breakfast. Then he walks to school with his friend Sam. At school, they learn math and science. After school, Tom plays football in the park. He comes home at five o''clock and does his homework. After dinner, he reads a book and goes to bed at nine.","exercises":[{"question":"What does Tom eat for breakfast?","options":["Toast and juice","Cereal and milk","Eggs and bacon","Pancakes"],"correct":0},{"question":"How does Tom go to school?","options":["By bus","By car","He walks","By bicycle"],"correct":2},{"question":"What does Tom do after school?","options":["Watches TV","Plays football","Goes shopping","Sleeps"],"correct":1},{"question":"What time does Tom come home?","options":["4 o''clock","5 o''clock","6 o''clock","7 o''clock"],"correct":1},{"question":"What does Tom do before bed?","options":["Plays games","Watches TV","Reads a book","Eats snacks"],"correct":2},{"question":"What is Tom''s favorite sport?","options":["Basketball","Soccer","Tennis","Baseball"],"correct":1},{"question":"What time does Tom usually wake up?","options":["6:30 AM","7:00 AM","7:30 AM","8:00 AM"],"correct":1},{"question":"What does Tom like to do on weekends?","options":["Visit friends","Go hiking","Play video games","Read books"],"correct":2},{"question":"What subject does Tom enjoy the most?","options":["Mathematics","Science","History","Art"],"correct":0},{"question":"Who is Tom''s best friend?","options":["Jake","Sam","Liam","Noah"],"correct":0},{"question":"What type of music does Tom prefer?","options":["Rock","Pop","Jazz","Classical"],"correct":1},{"question":"Where does Tom live?","options":["In a city","In a village","In a town","In the countryside"],"correct":2},{"question":"What is Tom''s favorite movie genre?","options":["Comedy","Horror","Action","Drama"],"correct":0},{"question":"What does Tom do before bed?","options":["Brushes his teeth","Reads a book","Watches TV","Plays games"],"correct":0},{"question":"How does Tom spend his summer vacation?","options":["Traveling","Working","Studying","Relaxing at home"],"correct":0},{"question":"What is Tom''s favorite snack?","options":["Chips","Fruit","Cookies","Chocolate"],"correct":3},{"question":"What does Tom want to be when he grows up?","options":["Doctor","Engineer","Artist","Teacher"],"correct":1},{"question":"What is Tom''s favorite season?","options":["Winter","Spring","Summer","Autumn"],"correct":2},{"question":"What does Tom do on his birthday?","options":["Have a party","Go out for dinner","Stay home","Travel"],"correct":0},{"question":"What is Tom''s pet''s name?","options":["Buddy","Max","Charlie","Rocky"],"correct":2}]}', 1),

('en', 'A2', 'reading', 'Reading Signs & Menus', 'Understand everyday signs and menus',
'{"type":"read_and_choose","instructions":"Read the sign or menu item and answer.","exercises":[{"sentence":"⚠️ CAUTION: Wet Floor","question":"What does this sign mean?","options":["The floor is dirty","The floor is wet, be careful","The floor is new","The floor is hot"],"correct":1},{"sentence":"🍕 Pizza — $8 | 🍔 Burger — $6 | 🥤 Juice — $3","question":"How much is a burger?","options":["$3","$6","$8","$10"],"correct":1},{"sentence":"🚫 No Swimming","question":"What can you NOT do here?","options":["Running","Swimming","Walking","Sitting"],"correct":1},{"sentence":"🕐 Open: 9 AM — 6 PM","question":"When does the place close?","options":["5 PM","6 PM","7 PM","8 PM"],"correct":1},{"sentence":"📧 Email us at info@school.com","question":"How can you contact them?","options":["By phone","By email","In person","By mail"],"correct":1},{"sentence":"🚪 Please Keep Door Closed","question":"What should you do with the door?","options":["Leave it open","Keep it closed","Push it hard","Lock it"],"correct":1},{"sentence":"⚠️ Danger: High Voltage","question":"What does this sign warn you about?","options":["Low temperature","High voltage electricity","Heavy machinery","Water hazards"],"correct":1},{"sentence":"🍦 Ice Cream — $4 | 🍰 Cake — $5 | 🍪 Cookie — $2","question":"How much does an ice cream cost?","options":["$2","$4","$5","$6"],"correct":1},{"sentence":"🚫 No Parking","question":"What is prohibited in this area?","options":["Parking","Bicycling","Walking","Running"],"correct":0},{"sentence":"🔞 18+ Only","question":"Who is allowed here?","options":["Children","Teens","Adults","Everyone"],"correct":2},{"sentence":"🕖 Opening Hours: 9 AM - 5 PM","question":"When does this place open?","options":["8 AM","9 AM","10 AM","All day"],"correct":1},{"sentence":"📶 Free Wi-Fi Available","question":"What service is offered here?","options":["Paid internet","Free Wi-Fi","No internet","Limited internet"],"correct":1},{"sentence":"🚭 No Smoking","question":"What is not allowed here?","options":["Smoking","Eating","Drinking","Talking"],"correct":0},{"sentence":"🚌 Bus Stop","question":"What is this location for?","options":["Train station","Bus stop","Taxi stand","Parking lot"],"correct":1},{"sentence":"🍳 Breakfast Served Until 11 AM","question":"Until what time can you order breakfast?","options":["10 AM","11 AM","12 PM","All day"],"correct":1},{"sentence":"🛑 Stop","question":"What must you do at this sign?","options":["Go faster","Slow down","Stop","Turn left"],"correct":2},{"sentence":"🎟️ Ticket Prices: Adult — $10 | Child — $5","question":"How much is a ticket for a child?","options":["$5","$10","$15","$20"],"correct":0},{"sentence":"📅 Closed on Sundays","question":"When is this place not open?","options":["Saturdays","Mondays","Sundays","Fridays"],"correct":2},{"sentence":"🚴‍♂️ Bike Lane","question":"What is this lane for?","options":["Cars","Bikes","Pedestrians","Buses"],"correct":1},{"sentence":"🈲 No Entry","question":"What does this sign indicate?","options":["Entry allowed","No entry","Limited entry","Free entry"],"correct":1}]}', 2),

('en', 'A2', 'reading', 'Understanding Messages', 'Read and understand short messages',
'{"type":"read_and_choose","instructions":"Read the message and answer the question.","exercises":[{"sentence":"Hi Mom! I am at Sara''s house. I will come home at 5. Love, Tom","question":"Where is Tom?","options":["At school","At Sara''s house","At the park","At home"],"correct":1},{"sentence":"Dear class, there is no school tomorrow because of the holiday. Enjoy! — Mrs. Smith","question":"Why is there no school?","options":["It is raining","The teacher is sick","It is a holiday","The school is broken"],"correct":2},{"sentence":"Don''t forget: soccer practice at 4 PM on the big field!","question":"When is soccer practice?","options":["3 PM","4 PM","5 PM","6 PM"],"correct":1},{"sentence":"Happy Birthday, Lily! 🎂 Party at my house, Saturday at 3 PM. Bring your swimsuit!","question":"What should Lily bring?","options":["A gift","Food","A swimsuit","Books"],"correct":2},{"sentence":"Library books are due on Friday. Please return them on time.","question":"When should books be returned?","options":["Monday","Wednesday","Friday","Sunday"],"correct":2},{"sentence":"Hey Sarah! I just finished my homework. Let''s meet at the library at 3 PM. Cheers, Jake","question":"Where will Jake meet Sarah?","options":["At home","At the library","At the park","At school"],"correct":1},{"sentence":"Reminder: The school play starts at 7 PM in the auditorium. Be there early! — Mr. Johnson","question":"What time does the school play start?","options":["6 PM","7 PM","8 PM","7:30 PM"],"correct":1},{"sentence":"Hi Dad! I’m going to the basketball game tonight. I’ll be home late. Love, Kevin","question":"What is Kevin going to tonight?","options":["A concert","A movie","A basketball game","A party"],"correct":2},{"sentence":"Dear students, please remember to bring your books for the class discussion tomorrow. — Ms. Adams","question":"What should students bring for tomorrow''s class?","options":["Snacks","Books","Games","Sports equipment"],"correct":1},{"sentence":"Hi team! Practice is canceled today due to the rain. See you next week! — Coach Lisa","question":"Why is practice canceled?","options":["It''s too hot","There''s a holiday","It''s raining","The coach is sick"],"correct":2},{"sentence":"Hello! I will be at the dentist at 2 PM. Can we reschedule our meeting? — Emily","question":"What time is Emily''s dentist appointment?","options":["1 PM","2 PM","3 PM","4 PM"],"correct":1},{"sentence":"Attention: The science fair takes place this Friday in the gym. Don’t forget to bring your projects! — Principal Brown","question":"When is the science fair?","options":["This Thursday","This Saturday","This Friday","Next Monday"],"correct":2},{"sentence":"Hi there! We have a family dinner at Grandma''s house on Sunday. Can''t wait! — Lily","question":"When is the family dinner?","options":["Saturday","Sunday","Friday","Monday"],"correct":1},{"sentence":"Don''t forget to turn in your assignments by the end of the week! — Mr. Lee","question":"When are the assignments due?","options":["Today","Tomorrow","By the end of the week","Next week"],"correct":2},{"sentence":"Hi Tim! Our next meeting is on Monday at 6 PM. Please confirm your attendance. — Sam","question":"When is the next meeting?","options":["Saturday","Sunday","Monday","Tuesday"],"correct":2},{"sentence":"Dear parents, please join us for the open house this Thursday at 5 PM. — Mrs. Green","question":"When is the open house?","options":["This Wednesday","This Thursday","This Friday","Next Thursday"],"correct":1},{"sentence":"Hello everyone! The field trip is scheduled for next Tuesday. Don’t forget your lunch! — Ms. Taylor","question":"When is the field trip?","options":["This Tuesday","Next Tuesday","This Monday","Next Friday"],"correct":1},{"sentence":"Hi Mom! I will be late for dinner because of my soccer game. Love, Alex","question":"Why will Alex be late for dinner?","options":["He is watching a movie","He is playing soccer","He is studying","He is with friends"],"correct":1},{"sentence":"Reminder: The book club meets every Thursday at 7 PM at my house. Bring your favorite book! — Sarah","question":"When does the book club meet?","options":["Every Monday","Every Wednesday","Every Thursday","Every Saturday"],"correct":2},{"sentence":"Hi everyone! I will be out of town from Friday to Sunday. Let’s catch up next week! — Mark","question":"When will Mark be out of town?","options":["Monday to Wednesday","Friday to Sunday","Saturday to Monday","Thursday to Saturday"],"correct":1}]}', 3);

-- ============================================================
-- A2 WRITING LESSONS
-- ============================================================
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES

('en', 'A2', 'writing', 'Complete the Sentence', 'Type the missing word to complete sentences',
'{"type":"fill_blank_type","instructions":"Read the sentence and type the missing word.","exercises":[{"sentence":"I ___ to school every day.","expected":"go","hint":"How you travel to school"},{"sentence":"She ___ a red dress yesterday.","expected":"wore","hint":"Past tense of wear"},{"sentence":"They are ___ in the park.","expected":"playing","hint":"Having fun, -ing form"},{"sentence":"We ___ dinner at seven.","expected":"eat","hint":"What you do with food"},{"sentence":"He ___ his homework last night.","expected":"did","hint":"Past tense of do"},{"sentence":"He ___ breakfast at 8 AM.","expected":"eats","hint":"What you do with food in the morning"},{"sentence":"They ___ to the concert last night.","expected":"went","hint":"Past tense of go"},{"sentence":"I am ___ a book right now.","expected":"reading","hint":"What you do with pages, -ing form"},{"sentence":"She ___ her homework before dinner.","expected":"finished","hint":"Past tense of finish"},{"sentence":"We ___ to the beach on weekends.","expected":"go","hint":"Regular activity for fun"},{"sentence":"He ___ his bike to school yesterday.","expected":"rode","hint":"Past tense of ride"},{"sentence":"The cat is ___ on the sofa.","expected":"sleeping","hint":"What animals do when they rest, -ing form"},{"sentence":"I ___ a letter to my friend last week.","expected":"wrote","hint":"Past tense of write"},{"sentence":"They are ___ a movie tonight.","expected":"watching","hint":"What you do when you view films, -ing form"},{"sentence":"She ___ a beautiful song yesterday.","expected":"sang","hint":"Past tense of sing"},{"sentence":"We ___ a picnic in the park.","expected":"had","hint":"Past tense of have"},{"sentence":"He is ___ to music right now.","expected":"listening","hint":"What you do with sounds, -ing form"},{"sentence":"I ___ a new game last month.","expected":"played","hint":"Past tense of play"},{"sentence":"They ___ for the bus in the rain.","expected":"waited","hint":"Past tense of wait"},{"sentence":"She ___ her friends at the mall.","expected":"met","hint":"Past tense of meet"}]}', 1),

('en', 'A2', 'writing', 'Write About Yourself', 'Type short sentences about yourself',
'{"type":"guided_writing","instructions":"Answer each question by typing a complete sentence.","exercises":[{"question":"What is your favorite color?","starter":"My favorite color is","example":"My favorite color is blue.","hint":"Name any color"},{"question":"What do you like to eat?","starter":"I like to eat","example":"I like to eat pizza.","hint":"Name a food you enjoy"},{"question":"Where do you live?","starter":"I live in","example":"I live in a big city.","hint":"Name your city or town"},{"question":"What is your hobby?","starter":"My hobby is","example":"My hobby is reading books.","hint":"Something you enjoy doing"},{"question":"How many people are in your family?","starter":"There are","example":"There are four people in my family.","hint":"Count your family members"},{"question":"What is your favorite animal?","starter":"My favorite animal is","example":"My favorite animal is a dog.","hint":"Name any animal"},{"question":"What sport do you enjoy?","starter":"I enjoy playing","example":"I enjoy playing soccer.","hint":"Name a sport you like"},{"question":"What is your favorite season?","starter":"My favorite season is","example":"My favorite season is summer.","hint":"Name a season like winter or spring"},{"question":"What type of music do you like?","starter":"I like listening to","example":"I like listening to rock music.","hint":"Name a genre of music"},{"question":"What hobby do you have?","starter":"My hobby is","example":"My hobby is painting.","hint":"Name something you enjoy doing in your free time"},{"question":"What is your favorite movie?","starter":"My favorite movie is","example":"My favorite movie is Inception.","hint":"Name any movie you like"},{"question":"What do you like to do on weekends?","starter":"On weekends, I like to","example":"On weekends, I like to go hiking.","hint":"Name an activity you enjoy"},{"question":"What is your dream job?","starter":"My dream job is","example":"My dream job is to be a teacher.","hint":"Name a profession you aspire to"},{"question":"What is your favorite book?","starter":"My favorite book is","example":"My favorite book is Harry Potter.","hint":"Name any book you enjoy reading"},{"question":"What is your favorite drink?","starter":"My favorite drink is","example":"My favorite drink is lemonade.","hint":"Name a beverage you like"},{"question":"What place would you like to visit?","starter":"I would like to visit","example":"I would like to visit Japan.","hint":"Name a country or city"},{"question":"What is your favorite dessert?","starter":"My favorite dessert is","example":"My favorite dessert is ice cream.","hint":"Name a sweet treat you enjoy"},{"question":"What kind of clothes do you like to wear?","starter":"I like to wear","example":"I like to wear comfortable clothes.","hint":"Describe a type of clothing"},{"question":"What is your favorite subject in school?","starter":"My favorite subject is","example":"My favorite subject is mathematics.","hint":"Name a school subject you enjoy"},{"question":"What is your favorite type of weather?","starter":"My favorite type of weather is","example":"My favorite type of weather is sunny.","hint":"Describe a weather condition you like"}]}', 2),

('en', 'A2', 'writing', 'Short Descriptions', 'Write short descriptions of pictures',
'{"type":"guided_writing","instructions":"Look at the description and type a similar sentence.","exercises":[{"question":"Describe a sunny day ☀️","starter":"The weather is","example":"The weather is sunny and warm today.","hint":"Talk about how it looks and feels outside"},{"question":"Describe your best friend 👫","starter":"My best friend is","example":"My best friend is kind and funny.","hint":"Use adjectives to describe them"},{"question":"Describe your school 🏫","starter":"My school is","example":"My school is big and has a beautiful garden.","hint":"Talk about its size and features"},{"question":"Describe your bedroom 🛏️","starter":"My bedroom has","example":"My bedroom has a bed, a desk, and many books.","hint":"List things in your room"},{"question":"Describe your favorite animal 🐾","starter":"My favorite animal is","example":"My favorite animal is a dog because it is friendly.","hint":"Name the animal and say why you like it"},{"question":"Describe your favorite meal 🍽️","starter":"My favorite meal is","example":"My favorite meal is spaghetti with marinara sauce.","hint":"Mention the main ingredients and why you love it"},{"question":"Describe a rainy day 🌧️","starter":"The weather is","example":"The weather is cloudy and drizzly outside.","hint":"Talk about how it affects your mood or activities"},{"question":"Describe your pet 🐶","starter":"My pet is","example":"My pet is a playful cat with soft fur.","hint":"Include details about their behavior and appearance"},{"question":"Describe your favorite book 📚","starter":"My favorite book is","example":"My favorite book is a thrilling mystery novel.","hint":"Talk about the plot or the main character"},{"question":"Describe your hometown 🏙️","starter":"My hometown is","example":"My hometown is small and surrounded by mountains.","hint":"Mention its size and unique features"},{"question":"Describe a holiday celebration 🎉","starter":"The holiday celebration is","example":"The holiday celebration is filled with joy and colorful decorations.","hint":"Include what activities take place during the celebration"},{"question":"Describe your favorite sport ⚽","starter":"My favorite sport is","example":"My favorite sport is basketball because it''s fast-paced.","hint":"Mention what you enjoy about playing or watching it"},{"question":"Describe a family member 👨‍👩‍👦","starter":"My sister is","example":"My sister is creative and loves to paint.","hint":"Use adjectives to capture their personality"},{"question":"Describe a memorable vacation ✈️","starter":"My last vacation was","example":"My last vacation was relaxing and full of adventure.","hint":"Include where you went and what you did"},{"question":"Describe your favorite movie 🎬","starter":"My favorite movie is","example":"My favorite movie is an action film with amazing stunts.","hint":"Talk about the storyline or characters"},{"question":"Describe your dream job 💼","starter":"My dream job is","example":"My dream job is to be a travel writer who explores the world.","hint":"Explain what makes it appealing to you"},{"question":"Describe a beautiful landscape 🌄","starter":"The landscape is","example":"The landscape is breathtaking with rolling hills and a clear blue sky.","hint":"Talk about colors and natural features"},{"question":"Describe a favorite childhood memory 🧸","starter":"A favorite childhood memory is","example":"A favorite childhood memory is playing in the park with my friends.","hint":"Include details about who was there and what you did"},{"question":"Describe a talent you have 🎨","starter":"I am good at","example":"I am good at playing the guitar and writing songs.","hint":"Explain how you learned this talent"},{"question":"Describe a city you want to visit 🗺️","starter":"I want to visit","example":"I want to visit Paris because of its rich history and culture.","hint":"Mention what you would do there"}]}', 3);
